import { Form, InputNumber, Popover } from '@arco-design/web-react'
import { IconQuestionCircle } from '@arco-design/web-react/icon'
import { useTranslation } from 'react-i18next'
import { BAND_FIELDS, BAND_LABELS } from './helpers'

const FormItem = Form.Item

type ResumptionBandInputsProps = {
  /** 字段前缀，例如 `staffBO[0]` */
  fieldPrefix: string
  /** 分组标题（恢复期最少需求） */
  groupLabel: string
  required?: boolean
  /** 每档最小值 = ceil(BAU × minOperatingLevel / 100) */
  min?: number
  /** 每档最大值 = BAU requirement */
  max?: number
  /** 用于错误提示中标识所属条目，例如 "Staff Requirement 1" */
  staffLabel?: string
  /** 标题旁悬浮提示文案 */
  tooltip?: string
}

/**
 * 恢复期时间档输入（0-4H / 4-8H / 8H-48H / 2D-7D / 7D-14D），5 个整数输入排成一行。
 * 仅在分组标题上展示必填星号，单个档位不重复展示星号（与高保真一致）。
 */
const ResumptionBandInputs = ({
  fieldPrefix,
  groupLabel,
  required = true,
  min,
  max,
  staffLabel,
  tooltip,
}: ResumptionBandInputsProps) => {
  const { t } = useTranslation(['common'])

  return (
    <div className='resource-resumption-band'>
      <div className='resource-resumption-group-label'>
        {required && <span className='required-star'>*</span>}
        <span>{groupLabel}</span>
        {tooltip && (
          <Popover
            trigger='hover'
            position='top'
            content={
              <div style={{ maxWidth: 320, fontSize: 13, color: '#1d2129', lineHeight: 1.6 }}>
                {tooltip}
              </div>
            }
            popupStyle={{ background: '#fff' }}
          >
            <IconQuestionCircle
              style={{ color: '#86909c', cursor: 'help', flexShrink: 0 }}
            />
          </Popover>
        )}
      </div>
      <div className='resource-resumption-band-grid'>
        {BAND_LABELS.map((band, i) => (
          <FormItem
            key={band}
            label={band}
            field={`${fieldPrefix}.${BAND_FIELDS[i]}`}
            requiredSymbol={false}
            rules={[
              { required, message: t('common:pleaseEnter') },
              {
                validator: (value: any, callback: (error?: string) => void) => {
                  if (value == null || value === '') { callback(); return }
                  const num = Number(value)
                  if (max != null && num > max) {
                    callback(t('biaRecord:resourceRequirement.bandValueRange', { label: staffLabel ?? '', min: min ?? 0, max }))
                  } else if (min != null && num < min) {
                    callback(t('biaRecord:resourceRequirement.bandValueRange', { label: staffLabel ?? '', min, max: max ?? '∞' }))
                  } else {
                    callback()
                  }
                },
              },
            ]}
          >
            <InputNumber
              min={min ?? 0}
              max={max}
              precision={0}
              placeholder={t('common:pleaseEnter')}
            />
          </FormItem>
        ))}
      </div>
    </div>
  )
}

export default ResumptionBandInputs

